output_format.json_schema:
{
  "contract_metadata": {
    "contract_type": "dpa",
    "parties": ["Controller/Covered Entity Name", "Processor/Business Associate Name"],
    "effective_date": "YYYY-MM-DD" (or null if not found),
    "term_length": "Coterminous with MSA | Matches main agreement | X years | Perpetual | 'See main agreement dated YYYY-MM-DD'",
    "total_value": "N/A - Data Processing Amendment | Tied to MSA value | Included in main agreement | 'Not specified'",
    "has_exhibits": true|false,
    "is_signed": true|false,
    "document_pages": 0,

    // DPA-specific fields
    "dpa_type": "GDPR|CCPA|HIPAA|Combined",
    "applicable_regulations": ["GDPR", "CCPA", "HIPAA", "UK GDPR", "Swiss DPA", "Other"],
    "is_standalone": true|false,
    "main_agreement_reference": "MSA or main service agreement name/date"
  },

  // IMPORTANT: Guidance for DPA-specific base fields:
  // - term_length: DPAs typically match the main service agreement term. Examples:
  //   * "Coterminous with MSA" if explicitly stated
  //   * "Matches main agreement" if referenced
  //   * "See main agreement dated 2024-01-15" if specific reference
  //   * Actual term if stated independently (e.g., "3 years")
  //   * "Perpetual" if no end date and covers all processing
  // - total_value: DPAs typically don't have separate financial value. Examples:
  //   * "N/A - Data Processing Amendment" (most common)
  //   * "Tied to MSA value" if DPA is part of broader agreement
  //   * "Included in main agreement" for bundled pricing
  //   * Actual value only if DPA has separate pricing (rare)
  // - has_exhibits: Check for annexes/schedules containing:
  //   * Data categories and processing purposes (Annex A/Schedule 1)
  //   * List of sub-processors (Annex B/Schedule 2)
  //   * Technical and organizational security measures
  //   * Standard Contractual Clauses (SCCs)
  //   * Transfer mechanisms for international data transfers

  "key_terms": {
    "roles_and_scope": {
      "controller_name": "Entity acting as controller",
      "processor_name": "Entity acting as processor",
      "relationship_clarity": "Clear|Some ambiguity|Unclear",
      "data_categories": ["Personal contact info", "Financial data", "Health data", "Location data"],
      "processing_purposes": "Description of purposes for processing",
      "processing_scope": "Description of processing activities",
      "concerns": ["List specific concerns with roles or scope"],
      "extracted_text": "Section X.Y: Verbatim quote of key role definition"
    },

    "data_security": {
      "security_measures": "Description of technical and organizational measures",
      "encryption_required": "At rest and in transit|At rest only|In transit only|Not specified",
      "security_certifications": ["SOC 2 Type II", "ISO 27001", "None specified"],
      "access_controls": "Description of access control requirements",
      "gdpr_article_32_compliance": "Compliant|Partially compliant|Non-compliant|Cannot assess",
      "concerns": ["List specific concerns with security measures"],
      "extracted_text": "Section X.Y: Verbatim quote of security requirements"
    },

    "breach_notification": {
      "notification_timeframe": "XX hours from discovery",
      "gdpr_compliant": true|false|"N/A",
      "hipaa_compliant": true|false|"N/A",
      "notification_details_required": "Description of required breach notification content",
      "investigation_procedures": "Description of breach investigation process",
      "data_subject_notification": "Controller responsibility|Processor responsibility|Shared",
      "concerns": ["List specific concerns with breach notification"],
      "extracted_text": "Section X.Y: Verbatim quote of breach notification clause"
    },

    "data_subject_rights": {
      "access_requests_supported": true|false,
      "deletion_supported": true|false,
      "rectification_supported": true|false,
      "portability_supported": true|false,
      "response_timeframe": "XX days or 'Not specified'",
      "assistance_fees": "Included|Reasonable fees|Excessive fees|Not specified",
      "gdpr_chapter_iii_compliance": "Compliant|Partially compliant|Non-compliant",
      "concerns": ["List specific concerns with data subject rights"],
      "extracted_text": "Section X.Y: Verbatim quote of data subject rights clause"
    },

    "data_retention_deletion": {
      "retention_period": "Description of retention period",
      "termination_data_handling": "Return and delete|Delete only|Return only|Not specified",
      "deletion_timeframe": "XX days post-termination",
      "deletion_certification": "Provided|Not provided",
      "backup_data_addressed": true|false,
      "concerns": ["List specific concerns with retention/deletion"],
      "extracted_text": "Section X.Y: Verbatim quote of deletion clause"
    },

    "sub_processors": {
      "sub_processors_allowed": true|false,
      "consent_required": "Prior consent|General consent with notice|No consent required",
      "current_sub_processors_listed": true|false,
      "notice_period_new_sub_processors": "XX days or 'None'",
      "objection_rights": "Can object|Cannot object|N/A",
      "sub_processor_obligations": "Equivalent DPA obligations|Lesser obligations|Not specified",
      "concerns": ["List specific concerns with sub-processor terms"],
      "extracted_text": "Section X.Y: Verbatim quote of sub-processor clause"
    },

    "international_transfers": {
      "transfers_occur": true|false,
      "transfer_destinations": ["Country list or 'Not specified'"],
      "transfer_mechanism": "SCCs|Adequacy decision|BCRs|None specified|Not applicable",
      "scc_version": "EU 2021|Old version (pre-2021)|Not applicable",
      "transfer_impact_assessment": "Required|Not required|Not mentioned",
      "uk_swiss_addendums": "Included where required|Missing|Not applicable",
      "concerns": ["List specific concerns with international transfers"],
      "extracted_text": "Section X.Y: Verbatim quote of transfer clause"
    },

    "audit_rights": {
      "audit_rights_granted": true|false,
      "audit_frequency": "On demand|Annually|Xx per year|Not specified",
      "third_party_auditors_allowed": true|false,
      "audit_costs": "Processor pays|Controller pays|Shared|Not specified",
      "audit_scope_limitations": "No limitations|Some limitations|Heavily restricted",
      "concerns": ["List specific concerns with audit rights"],
      "extracted_text": "Section X.Y: Verbatim quote of audit rights clause"
    },

    "liability_indemnification": {
      "processor_liability": "Description of processor liability for data breaches",
      "liability_cap": "$XXX,XXX or Unlimited or 'See main agreement'",
      "processor_indemnifies_controller": true|false,
      "gdpr_fines_covered": true|false|"Unclear",
      "sub_processor_liability": "Processor liable|Not liable|Unclear",
      "concerns": ["List specific concerns with liability provisions"],
      "extracted_text": "Section X.Y: Verbatim quote of liability clause"
    },

    "other_terms": {
      "dpia_assistance": "Processor assists|No assistance required|Not mentioned",
      "regulatory_cooperation": "Processor cooperates with authorities|Not specified",
      "confidentiality": "Processor staff bound by confidentiality|Not specified",
      "staff_training": "Data protection training required|Not mentioned",
      "insurance": "Processor maintains data protection insurance|Not required|Not mentioned"
    }
  },

  "risk_assessment": {
    "overall_risk_level": "high|medium|low",
    "risk_score": 0-100,
    "risk_score_breakdown": {
      "gdpr_compliance": 0-100,
      "ccpa_compliance": 0-100,
      "hipaa_compliance": 0-100,
      "security_adequacy": 0-100,
      "data_subject_rights_support": 0-100
    },

    "red_flags": [
      {
        "id": "RF-001",
        "category": "GDPR|CCPA|HIPAA|Security|Breach_Notification|Data_Subject_Rights|Sub_Processors|International_Transfers|Other",
        "severity": "critical|high",
        "issue": "Brief description of the compliance gap or critical issue",
        "detail": "Detailed explanation of why this violates or risks violating regulation",
        "regulation_reference": "GDPR Article XX or CCPA Section XX or HIPAA Requirement XX",
        "clause_reference": "Section X.Y, Page Z or 'Missing provision'",
        "recommendation": "Specific action to take (add provision, revise, seek counsel)",
        "business_impact": "Explanation of regulatory or business consequences"
      }
    ],

    "yellow_flags": [
      {
        "id": "YF-001",
        "category": "GDPR|CCPA|HIPAA|Security|Breach_Notification|Data_Subject_Rights|Sub_Processors|International_Transfers|Other",
        "issue": "Brief description of the concern",
        "detail": "Explanation of why this warrants attention",
        "clause_reference": "Section X.Y, Page Z",
        "recommendation": "Suggested action or improvement"
      }
    ],

    "positive_findings": [
      {
        "category": "GDPR|CCPA|HIPAA|Security|Breach_Notification|Data_Subject_Rights|Sub_Processors|International_Transfers|Other",
        "finding": "Description of strong compliance provision",
        "why_positive": "Explanation of why this meets or exceeds requirements",
        "clause_reference": "Section X.Y"
      }
    ]
  },

  "compliance_checklist": {
    "gdpr_compliance": {
      "article_28_requirements_met": true|false|"N/A",
      "data_subject_rights_covered": true|false|"N/A",
      "breach_notification_compliant": true|false|"N/A",
      "international_transfer_safeguards": true|false|"N/A",
      "sub_processor_requirements_met": true|false|"N/A",
      "missing_elements": ["List any missing GDPR requirements"]
    },
    "ccpa_compliance": {
      "service_provider_restrictions": true|false|"N/A",
      "data_sale_prohibition": true|false|"N/A",
      "audit_rights_adequate": true|false|"N/A",
      "missing_elements": ["List any missing CCPA requirements"]
    },
    "hipaa_compliance": {
      "baa_required_elements_present": true|false|"N/A",
      "safeguards_adequate_for_phi": true|false|"N/A",
      "breach_notification_compliant": true|false|"N/A",
      "missing_elements": ["List any missing HIPAA requirements"]
    }
  },

  "human_review_required": {
    "required": true|false,
    "reasons": ["List reasons why human review is needed"],
    "specific_questions": ["Specific questions for privacy counsel to answer"],
    "priority": "urgent|high|normal",
    "jurisdiction_specific_issues": ["List any jurisdiction-specific compliance concerns"],
    "ambiguous_clauses": [
      {
        "clause": "Description of ambiguous provision",
        "why_ambiguous": "Explanation of the ambiguity",
        "possible_interpretations": ["Interpretation A", "Interpretation B"],
        "recommendation": "What should be clarified"
      }
    ]
  },

  "executive_summary": {
    "contract_overview": "One sentence describing the data processing relationship and data types",
    "key_findings": [
      "First critical finding (use prefix: HIGH RISK/MEDIUM RISK/LOW RISK/COMPLIANCE ISSUE/POSITIVE as appropriate)",
      "Second critical finding with specific GDPR/privacy risk",
      "Third critical finding if applicable (limit to 3-4 most important compliance items)"
    ],
    "recommendation": "Clear action: APPROVE / NEGOTIATE [specific items] / REJECT / SEEK LEGAL/DPO REVIEW"
  },

  "recommendations": [
    {
      "priority": "high|medium|low",
      "action": "approve|revise|reject|clarify|seek_legal_review",
      "description": "Specific recommendation",
      "rationale": "Why this action is important from compliance perspective"
    }
  ],

  "next_steps": "Specific immediate actions for privacy/legal/infosec team",

  "confidence_score": 0-100,
  "confidence_explanation": "Brief explanation of why confidence is at this level (note jurisdiction-specific uncertainties)"
}

example.analysis_output:
{
  "data_subject_rights": {
    "access_requests_supported": false,
    "deletion_supported": false,
    "rectification_supported": false,
    "portability_supported": false,
    "concerns": [
      "No provisions for data subject access requests (GDPR Article 15)",
      "No provisions for right to erasure/deletion (GDPR Article 17)",
      "No provisions for right to rectification (GDPR Article 16)",
      "No provisions for data portability (GDPR Article 20)",
      "DPA missing entire GDPR Chapter III data subject rights support"
    ]
  },
  "breach_notification": {
    "notification_timeframe": "Not specified",
    "gdpr_compliant": false,
    "concerns": [
      "No breach notification procedure defined",
      "Missing required 72-hour notification timeframe (GDPR Article 33)",
      "No specification of breach notification content requirements"
    ]
  },
  "risk_assessment": {
    "overall_risk_level": "high",
    "risk_score": 90,
    "red_flags": [
      {
        "category": "GDPR",
        "severity": "critical",
        "issue": "Missing required GDPR data subject rights and breach notification provisions",
        "detail": "This DPA is missing critical GDPR Article 28(3) requirements. There are no provisions for processor to assist controller with data subject rights (access, deletion, rectification, portability) as required by GDPR Articles 15-20. There is no breach notification procedure or 72-hour timeframe as required by Article 33. These are not optional provisions - GDPR Article 28 mandates that DPAs include these terms. Using this DPA for EU personal data processing would constitute GDPR non-compliance.",
        "regulation_reference": "GDPR Article 28(3)(e) - data subject rights assistance; Article 28(3)(f) - breach notification; Article 33 - 72-hour timeframe",
        "clause_reference": "Missing provisions",
        "recommendation": "MUST ADD: (1) Data subject rights assistance provisions covering access, deletion, rectification, portability with reasonable response timeframes (30 days or less), (2) Breach notification within 72 hours with detailed content requirements, (3) Breach investigation and remediation procedures.",
        "business_impact": "GDPR non-compliance; potential regulatory fines up to €20 million or 4% of global revenue; inability to meet data subject requests; breach notification violations"
      }
    ]
  }
}

{
  "international_transfers": {
    "transfers_occur": true,
    "transfer_destinations": ["United States", "Asia-Pacific regions (unspecified)"],
    "transfer_mechanism": "None specified",
    "scc_version": "Not applicable - no SCCs present",
    "transfer_impact_assessment": "Not mentioned",
    "concerns": [
      "International data transfers to US and Asia-Pacific without safeguards",
      "No Standard Contractual Clauses (SCCs) incorporated",
      "No adequacy decision or alternative transfer mechanism specified",
      "Violates GDPR Chapter V requirements for international transfers"
    ]
  },
  "risk_assessment": {
    "overall_risk_level": "high",
    "risk_score": 95,
    "red_flags": [
      {
        "category": "International_Transfers",
        "severity": "critical",
        "issue": "International data transfers to third countries without GDPR-compliant safeguards",
        "detail": "This DPA allows processor to transfer EEA personal data to United States and unspecified Asia-Pacific countries without any GDPR Chapter V transfer mechanisms. Following the Schrems II decision (2020), transfers to US and other third countries require Standard Contractual Clauses (SCCs) at minimum, often with supplementary measures based on Transfer Impact Assessment. Transfers without adequate safeguards violate GDPR Article 44 and constitute serious non-compliance. This could result in data processing suspension orders from EU regulators.",
        "regulation_reference": "GDPR Articles 44-49 (Chapter V - Transfers to Third Countries); Article 46 - SCCs requirement; EDPB Recommendations 01/2020 on supplementary measures",
        "clause_reference": "Section 3.2 - Data Storage Locations",
        "recommendation": "MUST ADD: (1) EU Standard Contractual Clauses (2021 version) for all transfers to US and other third countries, (2) Transfer Impact Assessment for high-risk transfers, (3) Supplementary security measures where required, (4) UK and Swiss addendums if processing UK/Swiss data. ALTERNATIVE: Limit data processing to EEA only.",
        "business_impact": "GDPR Article 44 violation; risk of regulatory enforcement action; possible suspension of data transfers; regulatory fines; customer contract breaches if customers require GDPR compliance"
      }
    ]
  }
}

{
  "breach_notification": {
    "notification_timeframe": "48 hours from discovery",
    "gdpr_compliant": true,
    "concerns": []
  },
  "data_subject_rights": {
    "access_requests_supported": true,
    "deletion_supported": true,
    "response_timeframe": "15 business days",
    "gdpr_chapter_iii_compliance": "Compliant",
    "concerns": []
  },
  "sub_processors": {
    "consent_required": "Prior written consent",
    "notice_period_new_sub_processors": "30 days",
    "objection_rights": "Can object",
    "concerns": []
  },
  "international_transfers": {
    "transfers_occur": true,
    "transfer_mechanism": "SCCs",
    "scc_version": "EU 2021 (Module 2)",
    "concerns": []
  },
  "data_retention_deletion": {
    "termination_data_handling": "Delete or return",
    "deletion_timeframe": "30 days post-termination",
    "deletion_certification": "Provided",
    "concerns": []
  },
  "risk_assessment": {
    "overall_risk_level": "low",
    "risk_score": 15,
    "positive_findings": [
      {
        "category": "GDPR",
        "finding": "Comprehensive GDPR-compliant DPA with all required Article 28(3) provisions",
        "why_positive": "This DPA includes all mandatory GDPR provisions: (1) Breach notification within 48 hours (exceeds 72-hour requirement), (2) Data subject rights assistance with reasonable 15-day response time, (3) Sub-processor consent required with adequate 30-day notice, (4) Current SCCs (2021 version) for international transfers, (5) Prompt data deletion (30 days) with certification. This meets or exceeds GDPR requirements and represents best practice.",
        "clause_reference": "Sections 5.2, 6.1, 7.3, 8.1, 10.2"
      }
    ]
  },
  "compliance_checklist": {
    "gdpr_compliance": {
      "article_28_requirements_met": true,
      "data_subject_rights_covered": true,
      "breach_notification_compliant": true,
      "international_transfer_safeguards": true,
      "sub_processor_requirements_met": true,
      "missing_elements": []
    }
  }
}

{
  "executive_summary": {
    "contract_overview": "GDPR Data Processing Agreement as Processor for EU customer handling names, emails, and purchase history",
    "key_findings": [
      "COMPLIANCE ISSUE: Missing Standard Contractual Clauses (SCCs) required for transfers to US - GDPR violation risk",
      "HIGH RISK: Unlimited liability for GDPR breaches could expose us to millions in regulatory fines",
      "POSITIVE: Security measures (encryption, access controls) meet GDPR Article 32 technical requirements"
    ],
    "recommendation": "DO NOT SIGN without adding EU SCCs and negotiating liability cap for non-willful violations"
  },
  "risk_assessment": {
    "overall_risk_level": "high",
    "risk_score": 85
  }
}
